#:property AllowUnsafeBlocks=true

Span<nint> a = stackalloc nint[4];
a[0] = 10;
a[1] = 20;
a[2] = 30;
a[3] = 40;

Console.WriteLine($"Span<nint> length: {a.Length}, element size: {nint.Size} bytes");
for (int i = 0; i < a.Length; i++)
    Console.WriteLine($"  a[{i}] = {a[i]}");

Span<nuint> b = stackalloc nuint[3];
b[0] = 100;
b[1] = 200;
b[2] = 300;

Console.WriteLine($"Span<nuint> length: {b.Length}, element size: {nuint.Size} bytes");
for (int i = 0; i < b.Length; i++)
    Console.WriteLine($"  b[{i}] = {b[i]}");

